class CountMinSketch:
    def __init__(self, w: int, d: int):
        self.w = w
        self.d = d
        self.sketch = [[0] * w for _ in range(d)]

    def _indices(self, element):
        return [hash((element, i)) % self.w for i in range(self.d)]

    def update(self, element, count: int = 1) -> None:
        for row, col in enumerate(self._indices(element)):
            self.sketch[row][col] += count

    def query(self, element) -> int:
        return min(self.sketch[row][col] for row, col in enumerate(self._indices(element)))

