cms = CountMinSketch(w=10000, d=7)
for i in range(1000):
    cms.update(f'item_{i % 50}')  # 50 unique items, each ~20 times
for i in range(50):
    est = cms.query(f'item_{i}')
    assert est >= 20, f'item_{i} expected >= 20, got {est}'
